# AtradioError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class AtradioError(Exception):
    """
    Errors surfaced to host languages (one flat message; the SDK's typed errors
    are stringified at the boundary).
    """

    pass

_UniffiTempAtradioError = AtradioError

class AtradioError:  # type: ignore
    """
    Errors surfaced to host languages (one flat message; the SDK's typed errors
    are stringified at the boundary).
    """

    class Generic(_UniffiTempAtradioError):
        def __init__(self, message):
            super().__init__(", ".join([
                "message={!r}".format(message),
            ]))
            self.message = message

        def __repr__(self):
            return "AtradioError.Generic({})".format(str(self))
    _UniffiTempAtradioError.Generic = Generic # type: ignore

AtradioError = _UniffiTempAtradioError # type: ignore
del _UniffiTempAtradioError


class _UniffiConverterTypeAtradioError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return AtradioError.Generic(
                _UniffiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, AtradioError.Generic):
            _UniffiConverterString.check_lower(value.message)
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, AtradioError.Generic):
            buf.write_i32(1)
            _UniffiConverterString.write(value.message, buf)



class _UniffiConverterOptionalUInt32(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        if value is not None:
            _UniffiConverterUInt32.check_lower(value)

    @classmethod
    def write(cls, value, buf):
        if value is None:
            buf.write_u8(0)
            return

        buf.write_u8(1)
        _UniffiConverterUInt32.write(value, buf)

    @classmethod
    def read(cls, buf):
        flag = buf.read_u8()
        if flag == 0:
            return None
        elif flag == 1:
            return _UniffiConverterUInt32.read(buf)
        else:
            raise InternalError("Unexpected flag byte for optional type")



