# Async support

def favorite_rkey(station_id: "str") -> "str":
    """
    The deterministic favorite record key for a station id — identical across all
    atradio SDKs (Rust core, Go, TypeScript, and every FFI language).
    """

    _UniffiConverterString.check_lower(station_id)
    
    return _UniffiConverterString.lift(_uniffi_rust_call(_UniffiLib.uniffi_atradio_uniffi_fn_func_favorite_rkey,
        _UniffiConverterString.lower(station_id)))


